    'qna.modal.title':        { ko: '질문 상세',               en: 'Question Detail' },
    'qna.modal.close':        { ko: '닫기',                 en: 'Close' },
    'qna.modal.body.html':    { ko: '안녕하세요. 2026년 5월에 전기차(소형 SUV) 개인 구매를 계획 중입니다. 이때 신청 가능한 보조금이 국비·지방비 외에 추가로 있는지 알고 싶습니다. 또한 취득세 감면과 보조금의 연계 신청이 가능한지도 궁금합니다.',
                                en: 'Hello. I plan to purchase a small EV SUV privately in May 2026. Beyond national and local subsidies, are there other subsidies I can apply for? Can the acquisition-tax reduction be combined with the subsidy?' },
    'qna.modal.h5':           { ko: '담당 부서 답변 (1)',        en: 'Department Reply (1)' },
    'qna.modal.dept':         { ko: '보조금 정책과 · 담당자 김영희',  en: 'Subsidy Policy Div. · Officer Kim Young-hee' },
    'qna.modal.ans.html':     { ko: '안녕하세요. 보조금 정책과입니다. 2026년 전기차 개인 구매 시 신청 가능한 주요 지원은 아래와 같습니다.\n          <ul style="margin:10px 0 10px 18px;">\n            <li><strong>국비 보조금</strong> 최대 650만원</li>\n            <li><strong>지방비 보조금</strong> 지자체별 상이 (평균 350~700만원)</li>\n            <li><strong>세제 감면</strong> 취득세 최대 140만원 + 개별소비세 최대 300만원</li>\n            <li><strong>공채 매입 면제</strong> 최대 250만원 상당</li>\n          </ul>\n          보조금과 세제 감면은 별도로 적용되며, 차량 구매·등록 시 자동 반영됩니다. 자세한 사항은 <a href="subsidy-region.html" style="color:var(--color-secondary-700);font-weight:600;">지자체별 보조금 현황</a>을 확인해 주세요.',
                                en: 'Hello, this is the Subsidy Policy Division. Below are the main support items available for a 2026 private EV purchase.\n          <ul style="margin:10px 0 10px 18px;">\n            <li><strong>National Subsidy</strong> Up to KRW 6.5M</li>\n            <li><strong>Local Subsidy</strong> Varies by municipality (avg. KRW 3.5–7M)</li>\n            <li><strong>Tax Reduction</strong> Acquisition tax up to KRW 1.4M + Individual Consumption Tax up to KRW 3M</li>\n            <li><strong>Public Bond Exemption</strong> Worth up to KRW 2.5M</li>\n          </ul>\n          Subsidies and tax reductions are applied independently and reflected automatically at purchase/registration. For details, see the <a href="subsidy-region.html" style="color:var(--color-secondary-700);font-weight:600;">Local Subsidy Status</a>.' },
    'qna.modal.helpful':      { ko: '이 답변이 도움되었나요?',     en: 'Was this answer helpful?' },
    'qna.modal.like':         { ko: '공감 248',              en: 'Like 248' },
    'qna.modal.ok':           { ko: '확인',                 en: 'OK' },


